namespace CheckoutWizardDemo;

public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

@* Collects shipping address fields; validates Name and Address are non-empty before advancing. *@

<div class="shipping-step">
    <h3>Shipping Information</h3>

    <label>
        Name
        <input value="@name" @onchange="e => name = e.Value?.ToString() ?? """ />
    </label>

    <label>
        Address
        <input value="@address" @onchange="e => address = e.Value?.ToString() ?? """ />
    </label>

    <label>
        City
        <input value="@city" @onchange="e => city = e.Value?.ToString() ?? """ />
    </label>

    <label>
        Zip Code
        <input value="@zip" @onchange="e => zip = e.Value?.ToString() ?? """ />
    </label>

    @if (!string.IsNullOrWhiteSpace(validationMessage))
    {
        <p class="validation-error">@validationMessage</p>
    }

    <button @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public ShippingInfo Shipping { get; set; } = default!;
    [Parameter] public EventCallback<ShippingInfo> OnNext { get; set; }

    private string name = "";
    private string address = "";
    private string city = "";
    private string zip = "";
    private string? validationMessage;

    protected override void OnParametersSet()
    {
        name = Shipping.Name;
        address = Shipping.Address;
        city = Shipping.City;
        zip = Shipping.ZipCode;
    }

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(name) || string.IsNullOrWhiteSpace(address))
        {
            validationMessage = "Name and Address are required.";
            return;
        }

        validationMessage = null;

        var result = new ShippingInfo
        {
            Name = name,
            Address = address,
            City = city,
            ZipCode = zip
        };

        await OnNext.InvokeAsync(result);
    }
}

@* Collects payment details; provides Back and Place Order actions. *@

<div class="payment-step">
    <h3>Payment Information</h3>

    <label>
        Card Number
        <input value="@cardNumber" @onchange="e => cardNumber = e.Value?.ToString() ?? """ />
    </label>

    <label>
        Expiry Date
        <input value="@expiryDate" @onchange="e => expiryDate = e.Value?.ToString() ?? """ />
    </label>

    <button @onclick="HandleBack">Back</button>
    <button @onclick="HandlePlaceOrder">Place Order</button>
</div>

@code {
    [Parameter, EditorRequired] public PaymentInfo Payment { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<PaymentInfo> OnPlaceOrder { get; set; }

    private string cardNumber = "";
    private string expiryDate = "";

    protected override void OnParametersSet()
    {
        cardNumber = Payment.CardNumber;
        expiryDate = Payment.ExpiryDate;
    }

    private async Task HandleBack()
    {
        await OnBack.InvokeAsync();
    }

    private async Task HandlePlaceOrder()
    {
        var result = new PaymentInfo
        {
            CardNumber = cardNumber,
            ExpiryDate = expiryDate
        };

        await OnPlaceOrder.InvokeAsync(result);
    }
}

@* Orchestrates the checkout flow: shipping → payment → order placed. *@

<div class="checkout-wizard">
    @if (step == Step.Shipping)
    {
        <ShippingStep Shipping="@order.Shipping" OnNext="HandleShippingNext" />
    }
    else if (step == Step.Payment)
    {
        <PaymentStep Payment="@order.Payment"
                     OnBack="HandlePaymentBack"
                     OnPlaceOrder="HandlePlaceOrder" />
    }
</div>

@code {
    [Parameter] public EventCallback<Order> OnOrderPlaced { get; set; }

    private enum Step { Shipping, Payment }

    private Step step = Step.Shipping;
    private Order order = new();

    private void HandleShippingNext(ShippingInfo shipping)
    {
        order.Shipping = shipping;
        step = Step.Payment;
    }

    private void HandlePaymentBack()
    {
        step = Step.Shipping;
    }

    private async Task HandlePlaceOrder(PaymentInfo payment)
    {
        order.Payment = payment;
        await OnOrderPlaced.InvokeAsync(order);
    }
}

